sql:
SELECT COUNT(*)
FROM temperature_measurements
WHERE register_id = 0 AND status = 'completed';

SELECT register_name
FROM registers
ORDER BY register_name;

SELECT COUNT(calibration_id) AS calibration_count
FROM calibrations
WHERE register_id = 0;

SELECT AVG(measurement_value) AS average_temperature
FROM temperature_measurements
WHERE register_id = 0;

SELECT register_name
FROM registers
ORDER BY register_name;

external_knowledge:
; The most recent calibration is considered the latest date when a register's calibration was performed; 
; The last access refers to the most recent date when a user interacted with a register;
; Average temperature is calculated from measurements taken within the past 30 days.

sql:
SELECT MAX(calibration_date)
  FROM calibrations
  WHERE register_id = 0;
